import anthropic
import time

client = anthropic.Anthropic()

# Submit 1000 classification tasks at 50% cost via the batch API
requests = [
    {
        "custom_id": f"msg-{i}",
        "params": {
            "model": "claude-haiku-4-5",
            "max_tokens": 10,
            "messages": [{"role": "user", "content": f"Classify sentiment: '{text}'"}],
        },
    }
    for i, text in enumerate(["Great product!", "Terrible service.", "Meh, it's okay."])
]

batch = client.messages.batches.create(requests=requests)
print(f"Batch ID: {batch.id}")

# Poll for completion (or set up a webhook)
while True:
    batch = client.messages.batches.retrieve(batch.id)
    if batch.processing_status == "ended":
        break
    print(f"Status: {batch.processing_status} — waiting...")
    time.sleep(30)

# Retrieve results
for result in client.messages.batches.results(batch.id):
    if result.result.type == "succeeded":
        print(f"{result.custom_id}: {result.result.message.content[0].text}")
